     1→//! View types and navigation for the FORGE TUI.
     2→//!
     3→//! Views represent the different screens/modes available in the dashboard.
     4→
     5→use std::fmt;
     6→
     7→/// Available views in the FORGE dashboard.
     8→///
     9→/// Each view represents a distinct screen with its own content and interactions.
    10→/// Views can be switched using hotkeys or the Tab key to cycle.
    11→#[derive(Debug, Clone, Copy, PartialEq, Eq, Default)]
    12→pub enum View {
    13→    /// Overview/dashboard showing summary of all components
    14→    #[default]
    15→    Overview,
    16→    /// Worker pool management and status
    17→    Workers,
    18→    /// Task queue and bead management
    19→    Tasks,
    20→    /// Cost analytics and optimization
    21→    Costs,
    22→    /// Performance metrics and statistics
    23→    Metrics,
    24→    /// FORGE internal performance (event loop, render time, memory)
    25→    Perf,
    26→    /// Activity log viewer
    27→    Logs,
    28→    /// Subscription tracking and utilization
    29→    Subscriptions,
    30→    /// Worker health alerts and notifications
    31→    Alerts,
    32→    /// Conversational chat interface (activated with `:`)
    33→    Chat,
    34→}
    35→
    36→impl View {
    37→    /// Returns the hotkey character for this view.
    38→    pub fn hotkey(&self) -> char {
    39→        match self {
    40→            View::Overview => 'o',
    41→            View::Workers => 'w',
    42→            View::Tasks => 't',
    43→            View::Costs => 'c',
    44→            View::Metrics => 'm',
    45→            View::Perf => 'p',
    46→            View::Logs => 'l',
    47→            View::Subscriptions => 'u',
    48→            View::Alerts => 'a',
    49→            View::Chat => ':',
    50→        }
    51→    }
    52→
    53→    /// Returns the display title for this view.
    54→    pub fn title(&self) -> &'static str {
    55→        match self {
    56→            View::Overview => "Overview",
    57→            View::Workers => "Workers",
    58→            View::Tasks => "Tasks",
    59→            View::Costs => "Costs",
    60→            View::Metrics => "Metrics",
    61→            View::Perf => "Perf",
    62→            View::Logs => "Logs",
    63→            View::Subscriptions => "Subscriptions",
    64→            View::Alerts => "Alerts",
    65→            View::Chat => "Chat",
    66→        }
    67→    }
    68→
    69→    /// Returns the hotkey hint for status bar display.
    70→    pub fn hotkey_hint(&self) -> String {
    71→        format!("[{}] {}", self.hotkey(), self.title())
    72→    }
    73→
    74→    /// All views in display order (for Tab cycling).
    75→    pub const ALL: [View; 10] = [
    76→        View::Overview,
    77→        View::Workers,
    78→        View::Tasks,
    79→        View::Costs,
    80→        View::Metrics,
    81→        View::Perf,
    82→        View::Logs,
    83→        View::Subscriptions,
    84→        View::Alerts,
    85→        View::Chat,
    86→    ];
    87→
    88→    /// Returns the next view in the cycle (for Tab navigation).
    89→    pub fn next(&self) -> View {
    90→        let idx = Self::ALL.iter().position(|v| v == self).unwrap_or(0);
    91→        Self::ALL[(idx + 1) % Self::ALL.len()]
    92→    }
    93→
    94→    /// Returns the previous view in the cycle (for Shift+Tab navigation).
    95→    pub fn prev(&self) -> View {
    96→        let idx = Self::ALL.iter().position(|v| v == self).unwrap_or(0);
    97→        if idx == 0 {
    98→            Self::ALL[Self::ALL.len() - 1]
    99→        } else {
   100→            Self::ALL[idx - 1]
   101→        }
   102→    }
   103→
   104→    /// Try to parse a view from a hotkey character.
   105→    pub fn from_hotkey(key: char) -> Option<View> {
   106→        match key.to_ascii_lowercase() {
   107→            'o' => Some(View::Overview),
   108→            'w' => Some(View::Workers),
   109→            't' => Some(View::Tasks),
   110→            'c' => Some(View::Costs),
   111→            'm' => Some(View::Metrics),
   112→            'p' => Some(View::Perf),
   113→            'l' => Some(View::Logs),
   114→            'u' => Some(View::Subscriptions),
   115→            'a' => Some(View::Alerts),
   116→            ':' => Some(View::Chat),
   117→            _ => None,
   118→        }
   119→    }
   120→}
   121→
   122→impl fmt::Display for View {
   123→    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
   124→        write!(f, "{}", self.title())
   125→    }
   126→}
   127→
   128→/// Focus state for panels within a view.
   129→///
   130→/// Tracks which panel has keyboard focus for navigation and highlighting.
   131→#[derive(Debug, Clone, Copy, PartialEq, Eq, Default)]
   132→pub enum FocusPanel {
   133→    /// No specific panel focused (view-level focus)
   134→    #[default]
   135→    None,
   136→    /// Worker pool panel
   137→    WorkerPool,
   138→    /// Subscription/usage panel
   139→    Subscriptions,
   140→    /// Task queue panel
   141→    TaskQueue,
   142→    /// Activity log panel
   143→    ActivityLog,
   144→    /// Cost breakdown panel
   145→    CostBreakdown,
   146→    /// Metrics charts panel
   147→    MetricsCharts,
   148→    /// Perf metrics panel
   149→    PerfCharts,
   150→    /// Chat input panel
   151→    ChatInput,
   152→    /// Alert list panel
   153→    AlertList,
   154→}
   155→
   156→impl FocusPanel {
   157→    /// Returns whether this panel should show a highlight border.
   158→    pub fn is_highlighted(&self) -> bool {
   159→        !matches!(self, FocusPanel::None)
   160→    }
   161→}
   162→
   163→/// Layout mode based on terminal dimensions.
   164→///
   165→/// The TUI adapts its layout based on available screen real estate.
   166→#[derive(Debug, Clone, Copy, PartialEq, Eq)]
   167→pub enum LayoutMode {
   168→    /// Ultra-wide layout (199+ cols): 3-column with all 6 panels visible.
   169→    /// Left (66 cols): Workers + Subscriptions
   170→    /// Middle (66 cols): Tasks + Activity
   171→    /// Right (65 cols): Costs + Actions
   172→    UltraWide,
   173→    /// Wide layout (120-198 cols): 2-column with 4 panels visible.
   174→    Wide,
   175→    /// Narrow layout (<120 cols): single-view mode.
   176→    Narrow,
   177→}
   178→
   179→impl LayoutMode {
   180→    /// Determine the layout mode based on terminal width.
   181→    pub fn from_width(width: u16) -> Self {
   182→        if width >= 199 {
   183→            LayoutMode::UltraWide
   184→        } else if width >= 120 {
   185→            LayoutMode::Wide
   186→        } else {
   187→            LayoutMode::Narrow
   188→        }
   189→    }
   190→
   191→    /// Get the minimum terminal height for this layout mode.
   192→    pub fn min_height(&self) -> u16 {
   193→        match self {
   194→            LayoutMode::UltraWide => 38,
   195→            LayoutMode::Wide => 30,
   196→            LayoutMode::Narrow => 20,
   197→        }
   198→    }
   199→
   200→    /// Check if the terminal dimensions meet the layout requirements.
   201→    pub fn meets_requirements(&self, width: u16, height: u16) -> bool {
   202→        let required_mode = Self::from_width(width);
   203→        let height_ok = height >= self.min_height();
   204→
   205→        // Mode is valid if it matches width requirement and height is sufficient
   206→        *self == required_mode && height_ok
   207→    }
   208→}
   209→
   210→#[cfg(test)]
   211→mod tests {
   212→    use super::*;
   213→
   214→    #[test]
   215→    fn test_view_hotkeys() {
   216→        assert_eq!(View::Overview.hotkey(), 'o');
   217→        assert_eq!(View::Workers.hotkey(), 'w');
   218→        assert_eq!(View::Tasks.hotkey(), 't');
   219→        assert_eq!(View::Costs.hotkey(), 'c');
   220→        assert_eq!(View::Metrics.hotkey(), 'm');
   221→        assert_eq!(View::Logs.hotkey(), 'l');
   222→        assert_eq!(View::Subscriptions.hotkey(), 'u');
   223→        assert_eq!(View::Alerts.hotkey(), 'a');
   224→        assert_eq!(View::Chat.hotkey(), ':');
   225→    }
   226→
   227→    #[test]
   228→    fn test_view_from_hotkey() {
   229→        assert_eq!(View::from_hotkey('o'), Some(View::Overview));
   230→        assert_eq!(View::from_hotkey('W'), Some(View::Workers)); // case insensitive
   231→        assert_eq!(View::from_hotkey('u'), Some(View::Subscriptions));
   232→        assert_eq!(View::from_hotkey('a'), Some(View::Alerts));
   233→        assert_eq!(View::from_hotkey(':'), Some(View::Chat));
   234→        assert_eq!(View::from_hotkey('x'), None);
   235→    }
   236→
   237→    #[test]
   238→    fn test_view_cycling() {
   239→        assert_eq!(View::Overview.next(), View::Workers);
   240→        assert_eq!(View::Chat.next(), View::Overview); // wraps around
   241→        assert_eq!(View::Overview.prev(), View::Chat); // wraps around
   242→        assert_eq!(View::Workers.prev(), View::Overview);
   243→    }
   244→
   245→    #[test]
   246→    fn test_view_titles() {
   247→        assert_eq!(View::Overview.title(), "Overview");
   248→        assert_eq!(View::Workers.title(), "Workers");
   249→        assert_eq!(View::Alerts.title(), "Alerts");
   250→        assert_eq!(View::Chat.title(), "Chat");
   251→    }
   252→
   253→    #[test]
   254→    fn test_hotkey_hint() {
   255→        assert_eq!(View::Overview.hotkey_hint(), "[o] Overview");
   256→        assert_eq!(View::Chat.hotkey_hint(), "[:] Chat");
   257→        assert_eq!(View::Alerts.hotkey_hint(), "[a] Alerts");
   258→    }
   259→
   260→    #[test]
   261→    fn test_default_view() {
   262→        assert_eq!(View::default(), View::Overview);
   263→    }
   264→
   265→    // ============================================================
   266→    // LayoutMode Tests
   267→    // ============================================================
   268→
   269→    #[test]
   270→    fn test_layout_mode_from_width_ultrawide() {
   271→        assert_eq!(LayoutMode::from_width(199), LayoutMode::UltraWide);
   272→        assert_eq!(LayoutMode::from_width(200), LayoutMode::UltraWide);
   273→        assert_eq!(LayoutMode::from_width(300), LayoutMode::UltraWide);
   274→    }
   275→
   276→    #[test]
   277→    fn test_layout_mode_from_width_wide() {
   278→        assert_eq!(LayoutMode::from_width(120), LayoutMode::Wide);
   279→        assert_eq!(LayoutMode::from_width(150), LayoutMode::Wide);
   280→        assert_eq!(LayoutMode::from_width(198), LayoutMode::Wide);
   281→    }
   282→
   283→    #[test]
   284→    fn test_layout_mode_from_width_narrow() {
