     1→//! Worker Panel widget with color-coded health and activity indicators.
     2→//!
     3→//! This module provides a rich widget for displaying worker information
     4→//! with proper color-coded health status and activity state indicators.
     5→
     6→use ratatui::{
     7→    buffer::Buffer,
     8→    layout::Rect,
     9→    style::{Color, Modifier, Style},
    10→    text::{Line, Span},
    11→    widgets::{Block, BorderType, Borders, Paragraph, Widget},
    12→};
    13→use std::collections::HashSet;
    14→
    15→use crate::data::WorkerData;
    16→use forge_core::activity_monitor::ActivityState;
    17→use forge_worker::health::{HealthLevel, WorkerHealthStatus};
    18→
    19→/// A worker panel widget with color-coded health indicators.
    20→pub struct WorkerPanel<'a> {
    21→    data: &'a WorkerData,
    22→    focused: bool,
    23→    /// Set of paused worker IDs
    24→    paused_workers: &'a HashSet<String>,
    25→    /// Currently selected worker index
    26→    selected_index: usize,
    27→}
    28→
    29→impl<'a> WorkerPanel<'a> {
    30→    /// Create a new worker panel.
    31→    pub fn new(data: &'a WorkerData) -> Self {
    32→        static EMPTY_SET: std::sync::OnceLock<HashSet<String>> = std::sync::OnceLock::new();
    33→        Self {
    34→            data,
    35→            focused: false,
    36→            paused_workers: EMPTY_SET.get_or_init(HashSet::new),
    37→            selected_index: 0,
    38→        }
    39→    }
    40→
    41→    /// Set focus state.
    42→    pub fn focused(mut self, focused: bool) -> Self {
    43→        self.focused = focused;
    44→        self
    45→    }
    46→
    47→    /// Set the paused workers set.
    48→    pub fn paused_workers(mut self, paused: &'a HashSet<String>) -> Self {
    49→        self.paused_workers = paused;
    50→        self
    51→    }
    52→
    53→    /// Set the selected worker index.
    54→    pub fn selected(mut self, index: usize) -> Self {
    55→        self.selected_index = index;
    56→        self
    57→    }
    58→
    59→    /// Get the color for a health level.
    60→    fn health_color(health: &WorkerHealthStatus) -> Color {
    61→        match health.health_level() {
    62→            HealthLevel::Healthy => Color::Green,
    63→            HealthLevel::Degraded => Color::Yellow,
    64→            HealthLevel::Unhealthy => Color::Red,
    65→        }
    66→    }
    67→
    68→    /// Get styled health indicator spans.
    69→    fn health_indicator_spans(health: Option<&WorkerHealthStatus>) -> Vec<Span<'static>> {
    70→        match health {
    71→            Some(h) => {
    72→                let color = Self::health_color(h);
    73→                let indicator = h.health_indicator();
    74→                vec![
    75→                    Span::styled(indicator, Style::default().fg(color).add_modifier(Modifier::BOLD)),
    76→                ]
    77→            }
    78→            None => vec![Span::styled("?", Style::default().fg(Color::DarkGray))],
    79→        }
    80→    }
    81→
    82→    /// Build the content lines for the panel.
    83→    fn build_lines(&self) -> Vec<Line<'static>> {
    84→        let mut lines = Vec::new();
    85→
    86→        if !self.data.is_loaded() {
    87→            lines.push(Line::from(Span::styled(
    88→                "Loading worker data...",
    89→                Style::default().fg(Color::DarkGray),
    90→            )));
    91→            return lines;
    92→        }
    93→
    94→        if !self.data.has_any_workers() {
    95→            lines.push(Line::from(Span::styled(
    96→                "No workers found.\n\n\
    97→                 Workers will appear here when they register\n\
    98→                 status files in ~/.forge/status/\n\n\
    99→                 [G] Spawn GLM  [S] Spawn Sonnet  [O] Spawn Opus  [K] Kill",
   100→                Style::default().fg(Color::DarkGray),
   101→            )));
   102→            return lines;
   103→        }
   104→
   105→        // Show health summary if we have health data
   106→        if !self.data.health_status.is_empty() {
   107→            let (healthy, degraded, unhealthy) = self.data.health_counts();
   108→            let total = healthy + degraded + unhealthy;
   109→
   110→            let mut summary_spans = vec![Span::raw("Health: ")];
   111→
   112→            // Healthy count (green)
   113→            summary_spans.push(Span::styled(
   114→                format!("{} ", healthy),
   115→                Style::default().fg(Color::Green).add_modifier(Modifier::BOLD),
   116→            ));
   117→            summary_spans.push(Span::styled("●", Style::default().fg(Color::Green)));
   118→            summary_spans.push(Span::raw(" | "));
   119→
   120→            // Degraded count (yellow)
   121→            summary_spans.push(Span::styled(
   122→                format!("{} ", degraded),
   123→                Style::default().fg(Color::Yellow).add_modifier(Modifier::BOLD),
   124→            ));
   125→            summary_spans.push(Span::styled("◐", Style::default().fg(Color::Yellow)));
   126→            summary_spans.push(Span::raw(" | "));
   127→
   128→            // Unhealthy count (red)
   129→            summary_spans.push(Span::styled(
   130→                format!("{} ", unhealthy),
   131→                Style::default().fg(Color::Red).add_modifier(Modifier::BOLD),
   132→            ));
   133→            summary_spans.push(Span::styled("○", Style::default().fg(Color::Red)));
   134→            summary_spans.push(Span::raw(format!(" | {} total", total)));
   135→
   136→            lines.push(Line::from(summary_spans));
   137→        }
   138→
   139→        // Show activity summary (idle/working/stuck counts)
   140→        if !self.data.activity_status.is_empty() {
   141→            let (idle, working, stuck) = self.data.activity_counts();
   142→
   143→            let mut activity_spans = vec![Span::raw("Activity: ")];
   144→
   145→            // Working count (green)
   146→            activity_spans.push(Span::styled(
   147→                format!("{} ", working),
   148→                Style::default().fg(Color::Green).add_modifier(Modifier::BOLD),
   149→            ));
   150→            activity_spans.push(Span::styled("⟳", Style::default().fg(Color::Green)));
   151→            activity_spans.push(Span::raw(" | "));
   152→
   153→            // Idle count (cyan)
   154→            activity_spans.push(Span::styled(
   155→                format!("{} ", idle),
   156→                Style::default().fg(Color::Cyan).add_modifier(Modifier::BOLD),
   157→            ));
   158→            activity_spans.push(Span::styled("💤", Style::default().fg(Color::Cyan)));
   159→
   160→            // Stuck count (red) - only show if > 0
   161→            if stuck > 0 {
   162→                activity_spans.push(Span::raw(" | "));
   163→                activity_spans.push(Span::styled(
   164→                    format!("{} ", stuck),
   165→                    Style::default().fg(Color::Red).add_modifier(Modifier::BOLD),
   166→                ));
   167→                activity_spans.push(Span::styled("⚠️STUCK", Style::default().fg(Color::Red).add_modifier(Modifier::BOLD)));
   168→            }
   169→
   170→            lines.push(Line::from(activity_spans));
   171→        }
   172→
   173→        // Show paused workers summary if any are paused
   174→        let paused_count = self.paused_workers.len();
   175→        if paused_count > 0 {
   176→            let paused_spans = vec![
   177→                Span::raw("Paused: "),
   178→                Span::styled(
   179→                    format!("{} ", paused_count),
   180→                    Style::default().fg(Color::Magenta).add_modifier(Modifier::BOLD),
   181→                ),
   182→                Span::styled("⏸", Style::default().fg(Color::Magenta)),
   183→                Span::styled(
   184→                    " PAUSED",
   185→                    Style::default().fg(Color::Magenta).add_modifier(Modifier::BOLD),
   186→                ),
   187→            ];
   188→            lines.push(Line::from(paused_spans));
   189→        }
   190→
   191→        lines.push(Line::raw(""));
   192→
   193→        // Table header (with selection column)
   194→        lines.push(Line::from(vec![
   195→            Span::styled("┌───┬───┬─────────────────┬──────────┬──────────┬─────────────┐",
