   223→            let health_spans = Self::health_indicator_spans(health);
   224→
   225→            // Check if this worker is paused
   226→            let is_paused = self.paused_workers.contains(&worker.worker_id);
   227→
   228→            // Check if this row is selected
   229→            let is_selected = idx == self.selected_index;
   230→
   231→            // Determine row style based on state
   232→            let row_style = if is_selected && self.focused {
   233→                Style::default().fg(Color::Yellow).add_modifier(Modifier::BOLD)
   234→            } else if is_paused {
   235→                Style::default().fg(Color::Magenta)
   236→            } else {
   237→                Style::default().fg(Color::White)
   238→            };
   239→
   240→            // Selection/pause indicator
   241→            let sel_indicator = if is_selected && self.focused {
   242→                "▶"
   243→            } else if is_paused {
   244→                "⏸"
   245→            } else {
   246→                " "
   247→            };
   248→
   249→            let worker_id = truncate_string(&worker.worker_id, 15);
