   254→            let is_stuck = activity.map_or(false, |a| a.state == ActivityState::Stuck);
   255→
   256→            // Show "Paused" for paused workers, "STUCK" for stuck workers, otherwise actual status
   257→            let (status, status_style) = if is_paused {
   258→                ("Paused".to_string(), Style::default().fg(Color::Magenta))
