   260→                ("STUCK".to_string(), Style::default().fg(Color::Red).add_modifier(Modifier::BOLD))
   261→            } else {
   262→                (format_status(&worker.status), row_style)
   263→            };
   264→
   265→            // Show activity time for stuck workers
   266→            let task = if is_stuck {
   267→                activity
   268→                    .map(|a| format!("{}!", a.activity_age_string()))
   269→                    .unwrap_or_else(|| "-".to_string())
   270→            } else {
   271→                worker
   272→                    .current_task
