   285→            let row_content = if is_stuck {
   286→                // Special styling for stuck workers - red status
   287→                row_spans.extend(vec![
   288→                    Span::styled(format!(" │ {:<15} │ {:<8} │ ", worker_id, model), row_style),
   289→                    Span::styled(format!("{:<8}", status), status_style),
   290→                    Span::styled(format!(" │ {:<11} │", task), Style::default().fg(Color::Red)),
