   333→impl Widget for WorkerPanel<'_> {
   334→    fn render(self, area: Rect, buf: &mut Buffer) {
   335→        // Enhanced focus indicator: "▶" arrow for focused (clearer than diamond), "▪" for unfocused
   336→        let focus_icon = if self.focused { "▶" } else { "▪" };
   337→
   338→        // Border type: Double border for focused (highly visible), Normal for unfocused
   339→        let border_type = if self.focused {
   340→            BorderType::Double
   341→        } else {
   342→            BorderType::Plain
   343→        };
   344→
   345→        // Border style: bright cyan with bold for focused, dim for unfocused
   346→        let border_style = if self.focused {
   347→            Style::default()
   348→                .fg(Color::Cyan)
   349→                .add_modifier(Modifier::BOLD)
   350→        } else {
   351→            Style::default().fg(Color::DarkGray)
   352→        };
   353→
   354→        // Title style: bold + underlined for focused, dim for unfocused
   355→        let title_style = if self.focused {
   356→            Style::default()
   357→                .fg(Color::Cyan)
   358→                .add_modifier(Modifier::BOLD | Modifier::UNDERLINED)
   359→        } else {
   360→            Style::default().fg(Color::Rgb(80, 80, 80))
   361→        };
   362→
   363→        let lines = self.build_lines();
   364→        let paragraph = Paragraph::new(lines).block(
   365→            Block::default()
   366→                .borders(Borders::ALL)
   367→                .border_type(border_type)
   368→                .border_style(border_style)
   369→                .title(Span::styled(
   370→                    format!(" {} Worker Pool Management ", focus_icon),
   371→                    title_style,
   372→                )),
   373→        );
   374→
   375→        paragraph.render(area, buf);
   376→    }
   377→}
