   379→/// Format model name for table (shorter version).
   380→fn format_model_name_short(model: &str) -> String {
   381→    let lower = model.to_lowercase();
   382→    let name = if lower.contains("glm-47") || lower.contains("glm47") || lower.contains("glm-4.7") {
   383→        "GLM-4.7"
   384→    } else if lower.contains("sonnet") {
   385→        "Sonnet"
   386→    } else if lower.contains("opus") {
   387→        "Opus"
   388→    } else if lower.contains("haiku") {
   389→        "Haiku"
   390→    } else if model.is_empty() {
   391→        "Unknown"
   392→    } else {
   393→        model
   394→    };
   395→    truncate_string(name, 8)
   396→}
   397→
   398→/// Format worker status for display.
   399→fn format_status(status: &forge_core::types::WorkerStatus) -> String {
   400→    match status {
   401→        forge_core::types::WorkerStatus::Active => "Active".to_string(),
   402→        forge_core::types::WorkerStatus::Idle => "Idle".to_string(),
   403→        forge_core::types::WorkerStatus::Starting => "Starting".to_string(),
   404→        forge_core::types::WorkerStatus::Failed => "Failed".to_string(),
   405→        forge_core::types::WorkerStatus::Stopped => "Stopped".to_string(),
   406→        forge_core::types::WorkerStatus::Error => "Error".to_string(),
   407→        forge_core::types::WorkerStatus::Paused => "Paused".to_string(),
   408→    }
   409→}
   410→
   411→/// Truncate a string to a maximum length.
   412→fn truncate_string(s: &str, max_len: usize) -> String {
   413→    if s.len() <= max_len {
   414→        s.to_string()
   415→    } else if max_len > 2 {
   416→        format!("{}…", &s[..max_len - 1])
   417→    } else {
   418→        s[..max_len].to_string()
   419→    }
   420→}
   421→
   422→/// Format a compact health summary for narrow displays.
   423→pub fn format_health_summary_narrow(data: &WorkerData) -> String {
   424→    if !data.is_loaded() {
   425→        return "Loading...".to_string();
   426→    }
   427→
   428→    if !data.has_any_workers() {
   429→        return "No workers".to_string();
   430→    }
   431→
   432→    let (healthy, degraded, unhealthy) = data.health_counts();
   433→    let total = data.workers.len();
   434→
   435→    // Compact format for narrow displays
   436→    format!(
   437→        "{} workers: {}● {}◐ {}○",
   438→        total, healthy, degraded, unhealthy
   439→    )
   440→}
