   443→mod tests {
   444→    use super::*;
   445→
   446→    #[test]
   447→    fn test_truncate_string() {
   448→        assert_eq!(truncate_string("hello", 10), "hello");
   449→        assert_eq!(truncate_string("hello world", 5), "hell…");
   450→        assert_eq!(truncate_string("ab", 2), "ab");
   451→    }
   452→
   453→    #[test]
   454→    fn test_format_status() {
   455→        use forge_core::types::WorkerStatus;
   456→        assert_eq!(format_status(&WorkerStatus::Active), "Active");
   457→        assert_eq!(format_status(&WorkerStatus::Idle), "Idle");
   458→        assert_eq!(format_status(&WorkerStatus::Failed), "Failed");
   459→    }
   460→
   461→    #[test]
   462→    fn test_format_model_name_short() {
   463→        assert_eq!(format_model_name_short("claude-code-glm-47"), "GLM-4.7");
   464→        assert_eq!(format_model_name_short("sonnet-4.5"), "Sonnet");
   465→        assert_eq!(format_model_name_short("opus"), "Opus");
   466→        assert_eq!(format_model_name_short("haiku"), "Haiku");
   467→        assert_eq!(format_model_name_short(""), "Unknown");
   468→    }
