     1→//! Activity Log panel for real-time streaming display.
     2→//!
     3→//! This module provides a real-time activity log panel with:
     4→//! - Ring buffer for last N entries (configurable, default 100)
     5→//! - Color-coded log levels (info=white, warn=yellow, error=red)
     6→//! - Auto-scroll to latest entry with manual override
     7→//! - Scroll pause when user navigates up
     8→//!
     9→//! ## Architecture
    10→//!
    11→//! The panel receives activity events from multiple sources:
    12→//! - Worker status changes (spawn, stop, transition)
    13→//! - Task pickup/completion events
    14→//! - API call events (model, tokens, cost)
    15→//! - Health check results
    16→//! - Error and warning events
    17→
    18→use chrono::{DateTime, Local, Utc};
    19→use ratatui::{
    20→    buffer::Buffer,
    21→    layout::Rect,
    22→    style::{Color, Modifier, Style},
    23→    text::{Line, Span},
    24→    widgets::{Block, Borders, Paragraph, Widget},
    25→};
    26→use std::collections::VecDeque;
    27→
    28→use crate::log::LogLevel;
    29→
    30→/// Default ring buffer capacity for activity log (100 entries per spec).
    31→pub const DEFAULT_ACTIVITY_CAPACITY: usize = 100;
    32→
    33→/// Activity event types for the log.
    34→#[derive(Debug, Clone, PartialEq, Eq)]
    35→pub enum ActivityEventType {
    36→    /// Worker spawned
    37→    WorkerSpawn,
    38→    /// Worker stopped
    39→    WorkerStop,
    40→    /// Worker status transition
    41→    WorkerTransition,
    42→    /// Task picked up
    43→    TaskPickup,
    44→    /// Task completed
    45→    TaskComplete,
    46→    /// Task failed
    47→    TaskFailed,
    48→    /// API call event
    49→    ApiCall,
    50→    /// Health check result
    51→    HealthCheck,
    52→    /// Config hot-reloaded
    53→    ConfigReload,
    54→    /// General info
    55→    Info,
    56→    /// Warning event
    57→    Warning,
    58→    /// Error event
    59→    Error,
    60→}
    61→
    62→impl ActivityEventType {
    63→    /// Get the icon/symbol for this event type.
    64→    pub fn icon(&self) -> &'static str {
    65→        match self {
    66→            ActivityEventType::WorkerSpawn => "▶",
    67→            ActivityEventType::WorkerStop => "⏹",
    68→            ActivityEventType::WorkerTransition => "⟳",
    69→            ActivityEventType::TaskPickup => "⤴",
    70→            ActivityEventType::TaskComplete => "✓",
    71→            ActivityEventType::TaskFailed => "✗",
    72→            ActivityEventType::ApiCall => "⚡",
    73→            ActivityEventType::HealthCheck => "♥",
    74→            ActivityEventType::ConfigReload => "🔄",
    75→            ActivityEventType::Info => "●",
    76→            ActivityEventType::Warning => "⚠",
    77→            ActivityEventType::Error => "✖",
    78→        }
    79→    }
    80→
    81→    /// Get the color for this event type.
    82→    pub fn color(&self) -> Color {
    83→        match self {
    84→            ActivityEventType::WorkerSpawn => Color::Green,
    85→            ActivityEventType::WorkerStop => Color::Yellow,
    86→            ActivityEventType::WorkerTransition => Color::Cyan,
    87→            ActivityEventType::TaskPickup => Color::Blue,
    88→            ActivityEventType::TaskComplete => Color::Green,
    89→            ActivityEventType::TaskFailed => Color::Red,
    90→            ActivityEventType::ApiCall => Color::Magenta,
    91→            ActivityEventType::HealthCheck => Color::Green,
    92→            ActivityEventType::ConfigReload => Color::LightCyan,
    93→            ActivityEventType::Info => Color::White,
    94→            ActivityEventType::Warning => Color::Yellow,
    95→            ActivityEventType::Error => Color::Red,
    96→        }
    97→    }
    98→
    99→    /// Convert from LogLevel to ActivityEventType.
   100→    pub fn from_log_level(level: LogLevel) -> Self {
   101→        match level {
   102→            LogLevel::Trace | LogLevel::Debug | LogLevel::Info => ActivityEventType::Info,
   103→            LogLevel::Warn => ActivityEventType::Warning,
   104→            LogLevel::Error => ActivityEventType::Error,
   105→        }
   106→    }
   107→}
   108→
   109→/// A single activity log entry.
   110→#[derive(Debug, Clone)]
   111→pub struct ActivityEntry {
   112→    /// Timestamp of the event
   113→    pub timestamp: DateTime<Utc>,
   114→    /// Type of activity
   115→    pub event_type: ActivityEventType,
   116→    /// Source of the event (worker ID, component, etc.)
   117→    pub source: Option<String>,
   118→    /// Log message
   119→    pub message: String,
   120→}
   121→
   122→impl ActivityEntry {
   123→    /// Create a new activity entry.
   124→    pub fn new(event_type: ActivityEventType, message: impl Into<String>) -> Self {
   125→        Self {
   126→            timestamp: Utc::now(),
   127→            event_type,
   128→            source: None,
   129→            message: message.into(),
   130→        }
   131→    }
   132→
   133→    /// Add a source to the entry.
   134→    pub fn with_source(mut self, source: impl Into<String>) -> Self {
   135→        self.source = Some(source.into());
   136→        self
   137→    }
   138→
   139→    /// Format the entry for display.
   140→    pub fn format_display(&self) -> String {
   141→        let time = self.timestamp.with_timezone(&Local).format("%H:%M:%S");
   142→        if let Some(ref source) = self.source {
   143→            format!("[{}] {}", source, self.message)
   144→        } else {
   145→            self.message.clone()
   146→        }
   147→    }
   148→}
   149→
   150→/// Activity log data with ring buffer.
   151→#[derive(Debug, Clone)]
   152→pub struct ActivityLogData {
   153→    /// Ring buffer of entries
   154→    entries: VecDeque<ActivityEntry>,
   155→    /// Maximum capacity
   156→    capacity: usize,
   157→    /// Total entries ever added
   158→    total_added: usize,
   159→    /// Current scroll offset (0 = auto-scroll to bottom)
   160→    scroll_offset: usize,
   161→    /// Whether auto-scroll is paused due to user navigation
   162→    auto_scroll_paused: bool,
   163→    /// Last update timestamp
   164→    last_update: Option<DateTime<Utc>>,
   165→}
   166→
   167→impl Default for ActivityLogData {
   168→    fn default() -> Self {
   169→        Self::new(DEFAULT_ACTIVITY_CAPACITY)
   170→    }
   171→}
   172→
   173→impl ActivityLogData {
   174→    /// Create a new activity log data with the specified capacity.
   175→    pub fn new(capacity: usize) -> Self {
   176→        Self {
   177→            entries: VecDeque::with_capacity(capacity),
   178→            capacity,
   179→            total_added: 0,
   180→            scroll_offset: 0,
   181→            auto_scroll_paused: false,
   182→            last_update: None,
   183→        }
   184→    }
   185→
   186→    /// Create with default capacity (100 entries).
   187→    pub fn with_default_capacity() -> Self {
   188→        Self::default()
   189→    }
   190→
   191→    /// Push a new entry to the log.
   192→    pub fn push(&mut self, entry: ActivityEntry) {
   193→        // If at capacity, remove oldest
   194→        if self.entries.len() >= self.capacity {
   195→            self.entries.pop_front();
   196→        }
   197→        self.entries.push_back(entry);
   198→        self.total_added += 1;
   199→        self.last_update = Some(Utc::now());
   200→
   201→        // If auto-scroll is active, scroll offset stays at 0 (bottom)
   202→        // If paused, increment offset to keep view stable
   203→        if self.auto_scroll_paused && self.scroll_offset > 0 {
   204→            self.scroll_offset += 1;
   205→        }
   206→    }
   207→
   208→    /// Push multiple entries.
   209→    pub fn push_batch(&mut self, entries: impl IntoIterator<Item = ActivityEntry>) {
   210→        for entry in entries {
   211→            self.push(entry);
   212→        }
   213→    }
   214→
   215→    /// Get the number of entries.
   216→    pub fn len(&self) -> usize {
   217→        self.entries.len()
   218→    }
   219→
   220→    /// Check if empty.
   221→    pub fn is_empty(&self) -> bool {
   222→        self.entries.is_empty()
   223→    }
   224→
   225→    /// Get the capacity.
   226→    pub fn capacity(&self) -> usize {
   227→        self.capacity
   228→    }
   229→
   230→    /// Get total entries ever added.
   231→    pub fn total_added(&self) -> usize {
   232→        self.total_added
   233→    }
   234→
   235→    /// Scroll up by N lines.
   236→    pub fn scroll_up(&mut self, n: usize) {
   237→        let max_scroll = self.entries.len().saturating_sub(1);
   238→        self.scroll_offset = (self.scroll_offset + n).min(max_scroll);
   239→        if self.scroll_offset > 0 {
   240→            self.auto_scroll_paused = true;
   241→        }
   242→    }
   243→
   244→    /// Scroll down by N lines.
   245→    pub fn scroll_down(&mut self, n: usize) {
   246→        self.scroll_offset = self.scroll_offset.saturating_sub(n);
   247→        if self.scroll_offset == 0 {
   248→            self.auto_scroll_paused = false;
   249→        }
   250→    }
   251→
   252→    /// Scroll to the bottom (resume auto-scroll).
   253→    pub fn scroll_to_bottom(&mut self) {
   254→        self.scroll_offset = 0;
   255→        self.auto_scroll_paused = false;
   256→    }
   257→
   258→    /// Scroll to the top.
   259→    pub fn scroll_to_top(&mut self) {
   260→        self.scroll_offset = self.entries.len().saturating_sub(1);
   261→        self.auto_scroll_paused = true;
   262→    }
   263→
   264→    /// Check if auto-scroll is paused.
   265→    pub fn is_auto_scroll_paused(&self) -> bool {
   266→        self.auto_scroll_paused
   267→    }
   268→
   269→    /// Get current scroll offset.
   270→    pub fn scroll_offset(&self) -> usize {
   271→        self.scroll_offset
   272→    }
   273→
   274→    /// Get visible entries for rendering.
   275→    ///
   276→    /// Returns entries in reverse order (newest first) with scroll offset applied.
   277→    pub fn visible_entries(&self, max_lines: usize) -> Vec<&ActivityEntry> {
   278→        let total = self.entries.len();
   279→        if total == 0 {
   280→            return Vec::new();
   281→        }
   282→
   283→        // Calculate start index based on scroll offset
   284→        // scroll_offset = 0 means show newest entries (bottom)
   285→        // scroll_offset > 0 means scroll back from newest
   286→        let start_idx = if self.scroll_offset >= total {
   287→            0
   288→        } else {
   289→            total.saturating_sub(self.scroll_offset + max_lines)
   290→        };
   291→
   292→        // Get entries from newest to oldest, bounded by max_lines
   293→        let end_idx = total.saturating_sub(self.scroll_offset);
   294→
   295→        self.entries
   296→            .iter()
   297→            .skip(start_idx)
   298→            .take(end_idx.saturating_sub(start_idx).min(max_lines))
   299→            .collect()
   300→    }
   301→
   302→    /// Get all entries (oldest first).
   303→    pub fn iter(&self) -> impl Iterator<Item = &ActivityEntry> {
   304→        self.entries.iter()
   305→    }
   306→
   307→    /// Clear all entries.
   308→    pub fn clear(&mut self) {
   309→        self.entries.clear();
   310→        self.scroll_offset = 0;
   311→        self.auto_scroll_paused = false;
   312→    }
   313→
   314→    /// Get the last entry.
   315→    pub fn last(&self) -> Option<&ActivityEntry> {
   316→        self.entries.back()
   317→    }
   318→
   319→    /// Check if we have any entries.
   320→    pub fn has_entries(&self) -> bool {
   321→        !self.entries.is_empty()
   322→    }
   323→
   324→    /// Get last update timestamp.
   325→    pub fn last_update(&self) -> Option<DateTime<Utc>> {
   326→        self.last_update
   327→    }
   328→}
