   330→/// Activity log panel widget.
   331→pub struct ActivityPanel<'a> {
   332→    data: &'a ActivityLogData,
   333→    focused: bool,
   334→}
   335→
   336→impl<'a> ActivityPanel<'a> {
   337→    /// Create a new activity panel.
   338→    pub fn new(data: &'a ActivityLogData) -> Self {
   339→        Self {
   340→            data,
   341→            focused: false,
   342→        }
   343→    }
   344→
   345→    /// Set focus state.
   346→    pub fn focused(mut self, focused: bool) -> Self {
   347→        self.focused = focused;
   348→        self
   349→    }
   350→
   351→    /// Format an entry for display with colors.
   352→    fn format_entry_line(&self, entry: &ActivityEntry) -> Line<'static> {
   353→        let _time = entry.timestamp.with_timezone(&Local).format("%H:%M:%S");
   354→        let icon = entry.event_type.icon();
   355→        let color = entry.event_type.color();
   356→
   357→        let mut spans = Vec::new();
   358→
   359→        // Timestamp (dim)
   360→        spans.push(Span::styled(
   361→            format!("{} ", _time),
   362→            Style::default().fg(Color::DarkGray),
   363→        ));
   364→
   365→        // Icon with event color
   366→        spans.push(Span::styled(
   367→            format!("{} ", icon),
   368→            Style::default().fg(color).add_modifier(Modifier::BOLD),
   369→        ));
   370→
   371→        // Source (if present) in cyan
   372→        if let Some(ref source) = entry.source {
   373→            spans.push(Span::styled(
   374→                format!("[{}] ", source),
   375→                Style::default().fg(Color::Cyan),
   376→            ));
   377→        }
   378→
   379→        // Message in appropriate color based on event type
   380→        let msg_color = match entry.event_type {
   381→            ActivityEventType::Error => Color::Red,
   382→            ActivityEventType::Warning => Color::Yellow,
   383→            _ => Color::White,
   384→        };
   385→        spans.push(Span::styled(entry.message.clone(), Style::default().fg(msg_color)));
   386→
   387→        Line::from(spans)
   388→    }
   389→}
   390→
   391→impl Widget for ActivityPanel<'_> {
   392→    fn render(self, area: Rect, buf: &mut Buffer) {
   393→        // Focus indicator icon: "◆" for focused, "◇" for unfocused
   394→        let focus_icon = if self.focused { "◆" } else { "◇" };
   395→
   396→        // Border style: bright cyan for focused, dim for unfocused
   397→        let border_style = if self.focused {
   398→            Style::default().fg(Color::LightCyan)
   399→        } else {
   400→            Style::default().fg(Color::DarkGray)
   401→        };
   402→
   403→        // Title style: bold + bright for focused, dim for unfocused
   404→        let title_style = if self.focused {
   405→            Style::default()
   406→                .fg(Color::LightCyan)
   407→                .add_modifier(Modifier::BOLD)
   408→        } else {
   409→            Style::default().fg(Color::DarkGray)
   410→        };
   411→
   412→        // Build title with status indicators and focus icon
   413→        let title = if self.data.is_auto_scroll_paused() {
   414→            format!(
   415→                " {} Activity Log [paused - {}/{}] ",
   416→                focus_icon,
   417→                self.data.scroll_offset(),
   418→                self.data.len()
   419→            )
   420→        } else if self.data.has_entries() {
   421→            format!(" {} Activity Log [{}] ", focus_icon, self.data.len())
   422→        } else {
   423→            format!(" {} Activity Log ", focus_icon)
   424→        };
   425→
   426→        let block = Block::default()
   427→            .borders(Borders::ALL)
   428→            .border_style(border_style)
   429→            .title(Span::styled(title, title_style));
   430→
   431→        let inner = block.inner(area);
   432→        block.render(area, buf);
   433→
   434→        // Handle empty state
   435→        if !self.data.has_entries() {
   436→            let empty_msg = Paragraph::new(
   437→                "No recent activity.\n\n\
   438→                 Activity will appear here as workers\n\
   439→                 start, complete tasks, and update status.\n\n\
   440→                 [↑/↓] Scroll  [G] Top  [Shift+G] Bottom",
   441→            )
   442→            .style(Style::default().fg(Color::Gray));
   443→            empty_msg.render(inner, buf);
   444→            return;
   445→        }
   446→
   447→        // Calculate how many lines we can display
   448→        let max_lines = inner.height as usize;
   449→
   450→        // Get visible entries (in reverse order for display)
   451→        let visible = self.data.visible_entries(max_lines);
   452→
   453→        // Build lines from entries (newest at bottom)
   454→        let lines: Vec<Line> = visible.into_iter().rev().map(|e| self.format_entry_line(e)).collect();
   455→
   456→        let paragraph = Paragraph::new(lines);
   457→        paragraph.render(inner, buf);
   458→    }
   459→}
   460→
   461→/// Compact activity summary for overview panel.
   462→pub struct ActivitySummaryCompact<'a> {
   463→    data: &'a ActivityLogData,
   464→}
   465→
   466→impl<'a> ActivitySummaryCompact<'a> {
   467→    /// Create a new compact activity summary.
   468→    pub fn new(data: &'a ActivityLogData) -> Self {
   469→        Self { data }
   470→    }
   471→}
   472→
   473→impl Widget for ActivitySummaryCompact<'_> {
   474→    fn render(self, area: Rect, buf: &mut Buffer) {
   475→        if !self.data.has_entries() {
   476→            let no_activity =
   477→                Paragraph::new("No activity").style(Style::default().fg(Color::Gray));
   478→            no_activity.render(area, buf);
   479→            return;
   480→        }
   481→
   482→        // Show last 3 entries in compact form
   483→        let entries: Vec<_> = self.data.entries.iter().rev().take(3).collect();
   484→
   485→        let mut lines = Vec::new();
   486→        for entry in entries {
   487→            let time = entry.timestamp.with_timezone(&Local).format("%H:%M");
   488→            let icon = entry.event_type.icon();
   489→            let color = entry.event_type.color();
