   873→            ]));
   874→            lines.push(Line::from(""));
   875→        }
   876→
   877→        // Header
   878→        lines.push(Line::from(vec![
   879→            Span::styled("Worker", Style::default().fg(Color::Gray)),
   880→            Span::raw("  "),
   881→            Span::styled("#", Style::default().fg(Color::Gray)),
