   964→impl Widget for CostPanel<'_> {
   965→    fn render(self, area: Rect, buf: &mut Buffer) {
   966→        // Focus indicator icon: "◆" for focused, "◇" for unfocused
   967→        let focus_icon = if self.focused { "◆" } else { "◇" };
   968→
   969→        // Border style: bright cyan for focused, dim for unfocused
   970→        let border_style = if self.focused {
   971→            Style::default().fg(Color::LightCyan)
   972→        } else {
   973→            Style::default().fg(Color::DarkGray)
   974→        };
   975→
   976→        // Title style: bold + bright for focused, dim for unfocused
   977→        let title_style = if self.focused {
   978→            Style::default()
   979→                .fg(Color::LightCyan)
   980→                .add_modifier(Modifier::BOLD)
   981→        } else {
   982→            Style::default().fg(Color::DarkGray)
   983→        };
   984→
   985→        let block = Block::default()
   986→            .borders(Borders::ALL)
   987→            .border_style(border_style)
   988→            .title(Span::styled(
   989→                format!(" {} Cost Analytics ", focus_icon),
   990→                title_style,
   991→            ));
   992→
   993→        let inner = block.inner(area);
   994→        block.render(area, buf);
   995→
   996→        // Handle special states
   997→        if self.data.is_loading {
   998→            let loading =
   999→                Paragraph::new("Loading cost data...").style(Style::default().fg(Color::Yellow));
  1000→            loading.render(inner, buf);
  1001→            return;
  1002→        }
  1003→
  1004→        if let Some(ref error) = self.data.error {
  1005→            let err =
  1006→                Paragraph::new(format!("Error: {}", error)).style(Style::default().fg(Color::Red));
  1007→            err.render(inner, buf);
  1008→            return;
  1009→        }
  1010→
  1011→        if !self.data.has_data() {
  1012→            let no_data = Paragraph::new(
  1013→                "No cost data available.\n\n\
  1014→                 Cost tracking requires:\n\
  1015→                 - forge-cost database initialized\n\
  1016→                 - Worker logs being parsed\n\n\
  1017→                 Run: forge costs init",
  1018→            )
  1019→            .style(Style::default().fg(Color::Gray));
  1020→            no_data.render(inner, buf);
  1021→            return;
  1022→        }
  1023→
  1024→        // Layout: Summary | Worker Costs | Model Table | Trend | Recommendations
  1025→        let rec_height = if self.data.has_recommendations() { 5 } else { 0 };
  1026→        let worker_height = if self.data.has_worker_costs() { 8 } else { 0 };
  1027→        let layout = Layout::default()
  1028→            .direction(Direction::Vertical)
  1029→            .constraints([
  1030→                Constraint::Length(11),     // Summary (increased for week line)
  1031→                Constraint::Length(worker_height), // Worker costs
  1032→                Constraint::Min(5),         // Model table
  1033→                Constraint::Length(4),      // Trend sparkline
  1034→                Constraint::Length(rec_height), // Recommendations
  1035→            ])
  1036→            .split(inner);
  1037→
  1038→        self.render_summary(layout[0], buf);
  1039→        if worker_height > 0 {
  1040→            self.render_worker_costs(layout[1], buf);
  1041→        }
  1042→        self.render_model_table(layout[2], buf);
  1043→        self.render_trend(layout[3], buf);
  1044→        if rec_height > 0 {
  1045→            self.render_recommendations(layout[4], buf);
  1046→        }
  1047→    }
  1048→}
