   199→/// Renders a sparkline from a series of values.
   200→pub fn render_sparkline(values: &[i64], width: usize) -> String {
   201→    if values.is_empty() {
   202→        return " ".repeat(width);
   203→    }
   204→
   205→    let blocks = ['▁', '▂', '▃', '▄', '▅', '▆', '▇', '█'];
   206→    let max = values.iter().cloned().fold(0i64, i64::max);
   207→    let min = values.iter().cloned().fold(i64::MAX, i64::min);
   208→    let range = (max - min) as f64;
   209→
   210→    // Sample values to fit width
   211→    let step = values.len() as f64 / width as f64;
   212→    let mut result = String::with_capacity(width);
   213→
   214→    for i in 0..width {
   215→        let idx = ((i as f64) * step).min(values.len() as f64 - 1.0) as usize;
   216→        let val = values[idx];
   217→
   218→        let normalized = if range > 0.0 {
   219→            ((val - min) as f64 / range).clamp(0.0, 1.0)
   220→        } else {
   221→            0.5
   222→        };
   223→
   224→        let block_idx = ((normalized * 7.0).round() as usize).min(7);
   225→        result.push(blocks[block_idx]);
   226→    }
   227→
   228→    result
   229→}
   230→
   231→/// Renders a horizontal bar chart.
   232→pub fn render_bar(
   233→    value: f64,
   234→    max: f64,
   235→    width: usize,
   236→    filled_char: char,
   237→    empty_char: char,
   238→) -> String {
   239→    let pct = if max > 0.0 {
   240→        (value / max).clamp(0.0, 1.0)
   241→    } else {
   242→        0.0
   243→    };
   244→    let filled = (pct * width as f64).round() as usize;
   245→    let empty = width.saturating_sub(filled);
   246→
   247→    format!(
   248→        "{}{}",
   249→        filled_char.to_string().repeat(filled),
   250→        empty_char.to_string().repeat(empty)
   251→    )
   252→}
   253→
   254→/// Format a duration in seconds to human-readable form.
   255→pub fn format_duration(secs: i64) -> String {
   256→    if secs < 60 {
   257→        format!("{}s", secs)
   258→    } else if secs < 3600 {
   259→        let mins = secs / 60;
   260→        let remaining_secs = secs % 60;
   261→        format!("{}m {}s", mins, remaining_secs)
   262→    } else {
   263→        let hours = secs / 3600;
   264→        let mins = (secs % 3600) / 60;
   265→        format!("{}h {}m", hours, mins)
   266→    }
   267→}
   268→
   269→/// Format a dollar amount for display.
   270→pub fn format_usd(amount: f64) -> String {
   271→    if amount >= 1000.0 {
   272→        format!("${:.2}K", amount / 1000.0)
   273→    } else if amount >= 100.0 {
   274→        format!("${:.1}", amount)
   275→    } else if amount >= 10.0 {
   276→        format!("${:.2}", amount)
   277→    } else if amount >= 1.0 {
   278→        format!("${:.3}", amount)
   279→    } else if amount > 0.0 {
   280→        format!("${:.4}", amount)
   281→    } else {
   282→        "$0.00".to_string()
   283→    }
   284→}
   285→
   286→/// Truncate model name for display.
   287→pub fn truncate_model_name(model: &str, max_len: usize) -> String {
   288→    // Common abbreviations
   289→    let name = model
   290→        .replace("claude-opus-4-5-20251101", "Opus-4.5")
   291→        .replace("claude-opus-4-6", "Opus-4.6")
   292→        .replace("claude-sonnet-4-5-20250929", "Sonnet-4.5")
   293→        .replace("claude-haiku-4-5-20251001", "Haiku-4.5")
   294→        .replace("glm-4.7", "GLM-4.7")
   295→        .replace("deepseek-", "DS-");
   296→
   297→    if name.len() <= max_len {
   298→        name
   299→    } else if max_len > 2 {
   300→        format!("{}…", &name[..max_len - 1])
   301→    } else {
   302→        name[..max_len].to_string()
   303→    }
   304→}
