   481→    /// Render the model efficiency comparison table with 5+ metrics.
   482→    fn render_model_comparison(&self, area: Rect, buf: &mut Buffer) {
   483→        // Use 7-day aggregated data if available
   484→        let models = if !self.data.model_performance_7day.is_empty() {
   485→            &self.data.model_performance_7day
   486→        } else {
   487→            &self.data.model_performance
   488→        };
   489→
   490→        if models.is_empty() {
   491→            let msg = Paragraph::new("No model data").style(Style::default().fg(Color::Gray));
   492→            msg.render(area, buf);
   493→            return;
   494→        }
   495→
   496→        // Sort by total cost (descending) to show most expensive models first
   497→        let mut sorted_models = models.clone();
   498→        sorted_models.sort_by(|a, b| b.total_cost_usd.partial_cmp(&a.total_cost_usd).unwrap_or(std::cmp::Ordering::Equal));
   499→
   500→        let rows: Vec<Row> = sorted_models
   501→            .iter()
   502→            .take(6)
   503→            .map(|m| {
   504→                let success_pct = (m.success_rate * 100.0) as i64;
   505→
   506→                // Format cache hit rate
   507→                let cache_pct = (m.cache_hit_rate * 100.0) as i64;
   508→
   509→                Row::new(vec![
   510→                    truncate_model_name(&m.model, 10),
   511→                    format!("{}", m.total_calls),
   512→                    format!("{}", m.tasks_completed),
   513→                    format!("{:.0}%", success_pct),
   514→                    format_usd(m.avg_cost_per_task),
   515→                    format!("{:.0}%", cache_pct),
   516→                ])
   517→            })
   518→            .collect();
   519→
   520→        let header = Row::new(vec!["Model", "Calls", "Done", "Success", "Cost/T", "Cache"])
   521→            .style(
   522→                Style::default()
   523→                    .fg(Color::Gray)
   524→                    .add_modifier(Modifier::BOLD),
   525→            )
   526→            .bottom_margin(0);
   527→
   528→        let widths = [
   529→            Constraint::Length(10),
   530→            Constraint::Length(5),
   531→            Constraint::Length(4),
   532→            Constraint::Length(6),
   533→            Constraint::Length(7),
   534→            Constraint::Length(5),
   535→        ];
   536→
   537→        let table = Table::new(rows, widths).header(header).column_spacing(1);
   538→
   539→        ratatui::widgets::Widget::render(table, area, buf);
   540→    }
