   598→        }
   599→
   600→        let sparkline = render_sparkline(&values, area.width.saturating_sub(14) as usize);
   601→
   602→        let total: i64 = values.iter().sum();
   603→        let avg = if !values.is_empty() {
   604→            total as f64 / values.len() as f64
   605→        } else {
   606→            0.0
   607→        };
   608→
   609→        let mut lines = Vec::new();
   610→        lines.push(Line::from(vec![
   611→            Span::styled("7-Day Trend", Style::default().fg(Color::Cyan)),
   612→            Span::raw("  "),
   613→            Span::styled(
   614→                format!("Total: {}", total),
   615→                Style::default().fg(Color::White),
   616→            ),
   617→            Span::raw("  "),
   618→            Span::styled(
   619→                format!("Avg: {:.1}/day", avg),
   620→                Style::default().fg(Color::DarkGray),
   621→            ),
   622→        ]));
   623→        lines.push(Line::from(Span::styled(
   624→            sparkline,
   625→            Style::default().fg(Color::Green),
   626→        )));
   627→
   628→        let paragraph = Paragraph::new(lines);
   629→        paragraph.render(area, buf);
   630→    }
   631→
   632→    /// Render the worker efficiency ranking.
   633→    fn render_worker_efficiency(&self, area: Rect, buf: &mut Buffer) {
   634→        let workers = if !self.data.worker_efficiency_7day.is_empty() {
   635→            &self.data.worker_efficiency_7day
   636→        } else {
   637→            &self.data.worker_efficiency
   638→        };
   639→
   640→        if workers.is_empty() {
   641→            let msg = Paragraph::new("No worker data").style(Style::default().fg(Color::Gray));
   642→            msg.render(area, buf);
   643→            return;
   644→        }
   645→
   646→        // Sort by tasks completed (descending)
   647→        let mut sorted_workers = workers.clone();
   648→        sorted_workers.sort_by(|a, b| b.tasks_completed.cmp(&a.tasks_completed));
   649→
   650→        let mut lines = Vec::new();
   651→        lines.push(Line::from(vec![
   652→            Span::styled(
   653→                "Worker Efficiency",
   654→                Style::default().fg(Color::Cyan).add_modifier(Modifier::BOLD),
   655→            ),
   656→            Span::raw(" (7-day)"),
   657→        ]));
   658→        lines.push(Line::from(""));
   659→
   660→        // Show top 6 workers
   661→        for worker in sorted_workers.iter().take(6) {
   662→            let success_color = if worker.success_rate >= 0.9 {
   663→                Color::Green
   664→            } else if worker.success_rate >= 0.7 {
   665→                Color::Yellow
   666→            } else {
   667→                Color::Red
   668→            };
   669→
   670→            // Calculate tasks per day (7-day period)
   671→            let tasks_per_day = worker.tasks_completed as f64 / 7.0;
   672→
   673→            let worker_name = if worker.worker_id.len() > 18 {
   674→                format!("{}…", &worker.worker_id[..15])
   675→            } else {
   676→                worker.worker_id.clone()
   677→            };
   678→
   679→            lines.push(Line::from(vec![
   680→                Span::styled(
   681→                    format!("{:<18}", worker_name),
   682→                    Style::default().fg(Color::White),
   683→                ),
   684→                Span::raw(" "),
   685→                Span::styled(
   686→                    format!("{:>3}", worker.tasks_completed),
   687→                    Style::default().fg(Color::Green),
   688→                ),
   689→                Span::raw(" tasks  "),
   690→                Span::styled(
   691→                    format!("{:>4.1}/d", tasks_per_day),
   692→                    Style::default().fg(Color::Cyan),
   693→                ),
   694→                Span::raw("  "),
   695→                Span::styled(
   696→                    format!("{:>5.1}%", worker.success_rate * 100.0),
   697→                    Style::default().fg(success_color),
   698→                ),
   699→                Span::raw("  "),
   700→                Span::styled(
   701→                    format_usd(worker.avg_cost_per_task),
   702→                    Style::default().fg(Color::Magenta),
   703→                ),
   704→            ]));
   705→        }
   706→
   707→        let paragraph = Paragraph::new(lines);
   708→        paragraph.render(area, buf);
   709→    }
   710→
   711→    /// Render compact worker efficiency for narrow layout.
   712→    fn render_worker_efficiency_compact(&self, area: Rect, buf: &mut Buffer) {
   713→        let workers = if !self.data.worker_efficiency_7day.is_empty() {
   714→            &self.data.worker_efficiency_7day
   715→        } else {
   716→            &self.data.worker_efficiency
   717→        };
   718→
   719→        if workers.is_empty() {
   720→            let msg = Paragraph::new("No worker data").style(Style::default().fg(Color::Gray));
   721→            msg.render(area, buf);
   722→            return;
   723→        }
   724→
   725→        let mut sorted_workers = workers.clone();
   726→        sorted_workers.sort_by(|a, b| b.tasks_completed.cmp(&a.tasks_completed));
   727→
   728→        // Create a single line summary
   729→        let top3: Vec<String> = sorted_workers
   730→            .iter()
   731→            .take(3)
   732→            .map(|w| {
   733→                let name = if w.worker_id.len() > 10 {
   734→                    &w.worker_id[..10]
   735→                } else {
   736→                    &w.worker_id
   737→                };
   738→                format!("{}:{}", name, w.tasks_completed)
   739→            })
   740→            .collect();
   741→
   742→        let summary = format!("Top Workers: {}", top3.join(" | "));
   743→
   744→        let line = Line::from(vec![
   745→            Span::styled("⚡ ", Style::default().fg(Color::Yellow)),
   746→            Span::styled(summary, Style::default().fg(Color::White)),
   747→        ]);
   748→
   749→        let paragraph = Paragraph::new(line);
   750→        paragraph.render(area, buf);
   751→    }
   752→}
