   754→impl Widget for MetricsPanel<'_> {
   755→    fn render(self, area: Rect, buf: &mut Buffer) {
   756→        // Focus indicator icon: "◆" for focused, "◇" for unfocused
   757→        let focus_icon = if self.focused { "◆" } else { "◇" };
   758→
   759→        // Border style: bright cyan for focused, dim for unfocused
   760→        let border_style = if self.focused {
   761→            Style::default().fg(Color::LightCyan)
   762→        } else {
   763→            Style::default().fg(Color::DarkGray)
   764→        };
   765→
   766→        // Title style: bold + bright for focused, dim for unfocused
   767→        let title_style = if self.focused {
   768→            Style::default()
   769→                .fg(Color::LightCyan)
   770→                .add_modifier(Modifier::BOLD)
   771→        } else {
   772→            Style::default().fg(Color::DarkGray)
   773→        };
   774→
   775→        let block = Block::default()
   776→            .borders(Borders::ALL)
   777→            .border_style(border_style)
   778→            .title(Span::styled(
   779→                format!(" {} Performance Analytics ", focus_icon),
   780→                title_style,
   781→            ));
   782→
   783→        let inner = block.inner(area);
   784→        block.render(area, buf);
   785→
   786→        // Handle special states
   787→        if self.data.is_loading {
   788→            let loading =
   789→                Paragraph::new("Loading metrics...").style(Style::default().fg(Color::Yellow));
   790→            loading.render(inner, buf);
   791→            return;
   792→        }
   793→
   794→        if let Some(ref error) = self.data.error {
   795→            let err =
   796→                Paragraph::new(format!("Error: {}", error)).style(Style::default().fg(Color::Red));
   797→            err.render(inner, buf);
   798→            return;
   799→        }
   800→
   801→        if !self.data.has_data() {
   802→            let no_data = Paragraph::new(
   803→                "No performance data available.\n\n\
   804→                 Metrics tracking requires:\n\
   805→                 - forge-cost database initialized\n\
   806→                 - Worker activity being logged\n\n\
   807→                 Run: forge costs init",
   808→            )
   809→            .style(Style::default().fg(Color::Gray));
   810→            no_data.render(inner, buf);
   811→            return;
   812→        }
   813→
   814→        // Determine layout based on available height
   815→        // For wider displays, use a 2-column layout
   816→        let is_wide = area.width >= 160;
   817→
   818→        if is_wide {
   819→            self.render_wide_layout(inner, buf);
   820→        } else {
   821→            self.render_narrow_layout(inner, buf);
   822→        }
   823→    }
   824→}
