   826→impl MetricsPanel<'_> {
   827→    /// Render wide layout (2 columns) for screens >= 160 columns
   828→    fn render_wide_layout(&self, area: Rect, buf: &mut Buffer) {
   829→        // Split into left and right columns
   830→        let columns = Layout::default()
   831→            .direction(Direction::Horizontal)
   832→            .constraints([Constraint::Percentage(50), Constraint::Percentage(50)])
   833→            .split(area);
   834→
   835→        // Left column: Summary + Histogram + 7-day Trend
   836→        let left_layout = Layout::default()
   837→            .direction(Direction::Vertical)
   838→            .constraints([
   839→                Constraint::Length(4),  // Summary
   840→                Constraint::Min(10),    // Histogram (24h)
   841→                Constraint::Length(4),  // 7-day Trend
   842→            ])
   843→            .split(columns[0]);
   844→
   845→        // Right column: Model Comparison + Worker Efficiency
   846→        let right_layout = Layout::default()
   847→            .direction(Direction::Vertical)
   848→            .constraints([
   849→                Constraint::Min(8),  // Model comparison
   850→                Constraint::Min(6),  // Worker efficiency
   851→            ])
   852→            .split(columns[1]);
   853→
   854→        self.render_summary(left_layout[0], buf);
   855→        self.render_histogram(left_layout[1], buf);
   856→        self.render_7day_trend(left_layout[2], buf);
   857→        self.render_model_comparison(right_layout[0], buf);
   858→        self.render_worker_efficiency(right_layout[1], buf);
   859→    }
   860→
   861→    /// Render narrow layout (single column) for screens < 160 columns
   862→    fn render_narrow_layout(&self, area: Rect, buf: &mut Buffer) {
   863→        let layout = Layout::default()
   864→            .direction(Direction::Vertical)
   865→            .constraints([
   866→                Constraint::Length(3), // Summary
   867→                Constraint::Min(6),    // Histogram
   868→                Constraint::Min(5),    // Model comparison
   869→                Constraint::Length(4), // 7-day Trend
   870→                Constraint::Min(4),    // Worker efficiency
   871→            ])
   872→            .split(area);
   873→
   874→        self.render_summary(layout[0], buf);
   875→        self.render_histogram(layout[1], buf);
   876→        self.render_model_comparison(layout[2], buf);
   877→        self.render_trend(layout[3], buf);
   878→        self.render_worker_efficiency(layout[4], buf);
   879→    }
   880→}
   881→
   882→/// Compact metrics summary widget for overview panel.
