     1→//! Subscription status tracking panel for the FORGE TUI.
     2→//!
     3→//! This module provides subscription usage visualization with:
     4→//! - Usage table for Claude Pro, ChatGPT Plus, Cursor Pro, DeepSeek
     5→//! - Color-coded progress bars showing usage percentage
     6→//! - Reset timers showing when quotas refresh
     7→//! - Recommended actions based on usage patterns
     8→
     9→use chrono::{DateTime, Duration, Utc};
    10→use ratatui::{
    11→    buffer::Buffer,
    12→    layout::{Constraint, Rect},
    13→    style::{Color, Modifier, Style},
    14→    text::{Line, Span},
    15→    widgets::{Block, Borders, Paragraph, Row, Table, Widget},
    16→};
    17→
    18→/// Subscription service types supported.
    19→#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash)]
    20→pub enum SubscriptionService {
    21→    /// Claude Pro subscription
    22→    ClaudePro,
    23→    /// ChatGPT Plus subscription
    24→    ChatGPTPlus,
    25→    /// Cursor Pro subscription
    26→    CursorPro,
    27→    /// DeepSeek API subscription
    28→    DeepSeekAPI,
    29→}
    30→
    31→impl SubscriptionService {
    32→    /// Display name for the service.
    33→    pub fn display_name(&self) -> &'static str {
    34→        match self {
    35→            SubscriptionService::ClaudePro => "Claude Pro",
    36→            SubscriptionService::ChatGPTPlus => "ChatGPT Plus",
    37→            SubscriptionService::CursorPro => "Cursor Pro",
    38→            SubscriptionService::DeepSeekAPI => "DeepSeek API",
    39→        }
    40→    }
    41→
    42→    /// Short name for compact display.
    43→    pub fn short_name(&self) -> &'static str {
    44→        match self {
    45→            SubscriptionService::ClaudePro => "Claude",
    46→            SubscriptionService::ChatGPTPlus => "ChatGPT",
    47→            SubscriptionService::CursorPro => "Cursor",
    48→            SubscriptionService::DeepSeekAPI => "DeepSeek",
    49→        }
    50→    }
    51→
    52→    /// All subscription services.
    53→    pub const ALL: [SubscriptionService; 4] = [
    54→        SubscriptionService::ClaudePro,
    55→        SubscriptionService::ChatGPTPlus,
    56→        SubscriptionService::CursorPro,
    57→        SubscriptionService::DeepSeekAPI,
    58→    ];
    59→}
    60→
    61→/// Recommended action for a subscription.
    62→#[derive(Debug, Clone, Copy, PartialEq, Eq)]
    63→pub enum SubscriptionAction {
    64→    /// On track with normal usage - no action needed
    65→    OnPace,
    66→    /// Accelerate usage to maximize value before reset
    67→    Accelerate,
    68→    /// Max out - use all remaining quota
    69→    MaxOut,
    70→    /// Active pay-per-use - just monitor spending
    71→    Active,
    72→    /// Paused or inactive subscription
    73→    Paused,
    74→    /// Over quota - wait for reset
    75→    OverQuota,
    76→}
    77→
    78→impl SubscriptionAction {
    79→    /// Icon for the action.
    80→    pub fn icon(&self) -> &'static str {
    81→        match self {
    82→            SubscriptionAction::OnPace => "📊",
    83→            SubscriptionAction::Accelerate => "🚀",
    84→            SubscriptionAction::MaxOut => "⚠️",
    85→            SubscriptionAction::Active => "💰",
    86→            SubscriptionAction::Paused => "⏸️",
    87→            SubscriptionAction::OverQuota => "🛑",
    88→        }
    89→    }
    90→
    91→    /// Description of the action.
    92→    pub fn description(&self) -> &'static str {
    93→        match self {
    94→            SubscriptionAction::OnPace => "On-Pace",
    95→            SubscriptionAction::Accelerate => "Accel",
    96→            SubscriptionAction::MaxOut => "MaxOut",
    97→            SubscriptionAction::Active => "Active",
    98→            SubscriptionAction::Paused => "Paused",
    99→            SubscriptionAction::OverQuota => "Over",
   100→        }
   101→    }
   102→
   103→    /// Color for the action.
   104→    pub fn color(&self) -> Color {
   105→        match self {
   106→            SubscriptionAction::OnPace => Color::Green,
   107→            SubscriptionAction::Accelerate => Color::Cyan,
   108→            SubscriptionAction::MaxOut => Color::Yellow,
   109→            SubscriptionAction::Active => Color::Green,
   110→            SubscriptionAction::Paused => Color::Gray,
   111→            SubscriptionAction::OverQuota => Color::Red,
   112→        }
   113→    }
   114→}
   115→
   116→/// Reset period type for subscriptions.
   117→#[derive(Debug, Clone, Copy, PartialEq, Eq)]
   118→pub enum ResetPeriod {
   119→    /// Hourly reset (e.g., ChatGPT 40 messages per 3 hours)
   120→    Hourly(u32),
   121→    /// Daily reset
   122→    Daily,
   123→    /// Weekly reset
   124→    Weekly,
   125→    /// Monthly reset
   126→    Monthly,
   127→    /// No reset (pay-per-use)
   128→    PayPerUse,
   129→}
   130→
   131→impl ResetPeriod {
   132→    /// Format the reset period for display.
   133→    pub fn display(&self) -> String {
   134→        match self {
   135→            ResetPeriod::Hourly(hours) => format!("{}hr", hours),
   136→            ResetPeriod::Daily => "Daily".to_string(),
   137→            ResetPeriod::Weekly => "Weekly".to_string(),
   138→            ResetPeriod::Monthly => "Monthly".to_string(),
   139→            ResetPeriod::PayPerUse => "Pay/Use".to_string(),
   140→        }
   141→    }
   142→}
   143→
   144→/// Status of a single subscription.
   145→#[derive(Debug, Clone)]
   146→pub struct SubscriptionStatus {
   147→    /// Service type
   148→    pub service: SubscriptionService,
   149→    /// Current usage (messages, requests, or tokens)
   150→    pub current_usage: u64,
   151→    /// Usage limit (None for pay-per-use)
   152→    pub limit: Option<u64>,
   153→    /// Unit of measurement (messages, requests, tokens)
   154→    pub unit: String,
   155→    /// When the quota resets
   156→    pub resets_at: Option<DateTime<Utc>>,
   157→    /// Reset period type
   158→    pub reset_period: ResetPeriod,
   159→    /// Whether the subscription is active
   160→    pub is_active: bool,
   161→    /// Daily spend for pay-per-use subscriptions
   162→    pub daily_spend: Option<f64>,
   163→    /// Last updated timestamp
   164→    pub last_updated: DateTime<Utc>,
   165→}
   166→
   167→impl SubscriptionStatus {
   168→    /// Create a new subscription status.
   169→    pub fn new(service: SubscriptionService) -> Self {
   170→        Self {
   171→            service,
   172→            current_usage: 0,
   173→            limit: None,
   174→            unit: "msgs".to_string(),
   175→            resets_at: None,
   176→            reset_period: ResetPeriod::Monthly,
   177→            is_active: false,
   178→            daily_spend: None,
   179→            last_updated: Utc::now(),
   180→        }
   181→    }
   182→
   183→    /// Set usage and limit.
   184→    pub fn with_usage(mut self, current: u64, limit: u64, unit: &str) -> Self {
   185→        self.current_usage = current;
   186→        self.limit = Some(limit);
   187→        self.unit = unit.to_string();
   188→        self
   189→    }
   190→
   191→    /// Set reset time.
   192→    pub fn with_reset(mut self, resets_at: DateTime<Utc>, period: ResetPeriod) -> Self {
   193→        self.resets_at = Some(resets_at);
   194→        self.reset_period = period;
   195→        self
   196→    }
   197→
   198→    /// Set as pay-per-use with daily spend.
   199→    pub fn with_pay_per_use(mut self, daily_spend: f64) -> Self {
   200→        self.limit = None;
   201→        self.daily_spend = Some(daily_spend);
   202→        self.reset_period = ResetPeriod::PayPerUse;
   203→        self
   204→    }
   205→
   206→    /// Set active status.
   207→    pub fn with_active(mut self, active: bool) -> Self {
   208→        self.is_active = active;
   209→        self
   210→    }
   211→
   212→    /// Get usage percentage (0-100).
   213→    pub fn usage_pct(&self) -> f64 {
   214→        match self.limit {
   215→            Some(limit) if limit > 0 => (self.current_usage as f64 / limit as f64) * 100.0,
   216→            _ => 0.0,
   217→        }
   218→    }
   219→
   220→    /// Get remaining usage.
   221→    pub fn remaining(&self) -> Option<u64> {
   222→        self.limit.map(|l| l.saturating_sub(self.current_usage))
   223→    }
   224→
   225→    /// Get time until reset.
   226→    pub fn time_until_reset(&self) -> Option<Duration> {
   227→        self.resets_at.map(|r| {
   228→            let now = Utc::now();
   229→            if r > now { r - now } else { Duration::zero() }
   230→        })
   231→    }
   232→
   233→    /// Format time until reset for display.
   234→    pub fn format_reset_timer(&self) -> String {
   235→        match self.time_until_reset() {
   236→            Some(duration) if duration > Duration::zero() => {
   237→                let days = duration.num_days();
   238→                let hours = duration.num_hours() % 24;
   239→                let minutes = duration.num_minutes() % 60;
   240→
   241→                if days > 0 {
   242→                    format!("{}d {}h", days, hours)
   243→                } else if hours > 0 {
   244→                    format!("{}h {}m", hours, minutes)
   245→                } else {
   246→                    format!("{}m", minutes)
   247→                }
   248→            }
   249→            Some(_) => "Resetting...".to_string(),
   250→            None => match self.reset_period {
   251→                ResetPeriod::PayPerUse => "Monthly".to_string(),
   252→                _ => "-".to_string(),
   253→            },
   254→        }
   255→    }
   256→
   257→    /// Determine the recommended action based on usage patterns.
   258→    pub fn recommended_action(&self) -> SubscriptionAction {
   259→        if !self.is_active {
   260→            return SubscriptionAction::Paused;
   261→        }
   262→
   263→        // Pay-per-use subscriptions are always "Active"
   264→        if matches!(self.reset_period, ResetPeriod::PayPerUse) {
   265→            return SubscriptionAction::Active;
   266→        }
   267→
   268→        let usage_pct = self.usage_pct();
   269→
   270→        // Check if over quota
   271→        if usage_pct >= 100.0 {
   272→            return SubscriptionAction::OverQuota;
   273→        }
   274→
   275→        // Calculate expected usage based on time remaining
   276→        if let Some(duration) = self.time_until_reset() {
   277→            let total_hours = match self.reset_period {
   278→                ResetPeriod::Hourly(h) => h as f64,
   279→                ResetPeriod::Daily => 24.0,
   280→                ResetPeriod::Weekly => 24.0 * 7.0,
   281→                ResetPeriod::Monthly => 24.0 * 30.0,
   282→                ResetPeriod::PayPerUse => return SubscriptionAction::Active,
   283→            };
   284→
   285→            let hours_remaining =
   286→                duration.num_hours() as f64 + (duration.num_minutes() % 60) as f64 / 60.0;
   287→            let hours_elapsed = total_hours - hours_remaining;
   288→            let expected_pct = if total_hours > 0.0 {
   289→                (hours_elapsed / total_hours) * 100.0
   290→            } else {
   291→                100.0
   292→            };
   293→
   294→            // Compare actual vs expected
   295→            let ratio = if expected_pct > 0.0 {
   296→                usage_pct / expected_pct
   297→            } else {
   298→                0.0
   299→            };
   300→
   301→            // Determine action based on ratio and remaining time
   302→            if usage_pct >= 95.0 {
   303→                SubscriptionAction::MaxOut
   304→            } else if ratio < 0.5 && usage_pct < 50.0 && hours_remaining < total_hours * 0.3 {
   305→                // Less than 30% time left but less than 50% used
   306→                SubscriptionAction::MaxOut
   307→            } else if ratio < 0.7 && usage_pct < 70.0 {
   308→                SubscriptionAction::Accelerate
   309→            } else {
   310→                SubscriptionAction::OnPace
   311→            }
   312→        } else {
   313→            // No reset time info - assume on pace
   314→            SubscriptionAction::OnPace
   315→        }
   316→    }
   317→
   318→    /// Get color for usage bar based on percentage.
   319→    pub fn usage_color(&self) -> Color {
   320→        let pct = self.usage_pct();
   321→        if pct >= 95.0 {
   322→            Color::Red
   323→        } else if pct >= 80.0 {
   324→            Color::LightRed
   325→        } else if pct >= 60.0 {
   326→            Color::Yellow
   327→        } else if pct >= 40.0 {
   328→            Color::Cyan
   329→        } else {
   330→            Color::Green
   331→        }
   332→    }
   333→}
