   426→/// Render a horizontal progress bar.
   427→pub fn render_usage_bar(pct: f64, width: usize, color: Color) -> Line<'static> {
   428→    let pct = pct.clamp(0.0, 100.0);
   429→    let filled = ((pct / 100.0) * width as f64).round() as usize;
   430→    let empty = width.saturating_sub(filled);
   431→
   432→    let filled_str: String = "█".repeat(filled);
   433→    let empty_str: String = "░".repeat(empty);
   434→
   435→    Line::from(vec![
   436→        Span::styled(filled_str, Style::default().fg(color)),
   437→        Span::styled(empty_str, Style::default().fg(Color::DarkGray)),
   438→    ])
   439→}
