   462→    /// Render the subscription table.
   463→    fn render_table(&self, area: Rect, buf: &mut Buffer) {
   464→        if self.data.subscriptions.is_empty() {
   465→            let msg = Paragraph::new("No subscription data available")
   466→                .style(Style::default().fg(Color::Gray));
   467→            msg.render(area, buf);
   468→            return;
   469→        }
   470→
   471→        // Build table rows
   472→        let rows: Vec<Row> = self
   473→            .data
   474→            .subscriptions
   475→            .iter()
   476→            .map(|sub| {
   477→                let service = sub.service.display_name();
   478→
   479→                // Usage column with bar
   480→                let usage_str = if let Some(limit) = sub.limit {
   481→                    format!("{}/{}", sub.current_usage, limit)
   482→                } else if let Some(spend) = sub.daily_spend {
   483→                    format!("${:.2}/d", spend)
   484→                } else {
   485→                    "-".to_string()
   486→                };
   487→
   488→                // Limit/unit column
   489→                let limit_str = if sub.limit.is_some() {
   490→                    sub.unit.clone()
   491→                } else {
   492→                    "∞".to_string()
   493→                };
   494→
   495→                // Reset timer
   496→                let reset_str = sub.format_reset_timer();
   497→
   498→                // Action with icon
   499→                let action = sub.recommended_action();
   500→                let action_str = format!("{} {}", action.icon(), action.description());
   501→
   502→                Row::new(vec![
   503→                    service.to_string(),
   504→                    usage_str,
   505→                    limit_str,
   506→                    reset_str,
   507→                    action_str,
   508→                ])
   509→                .style(if sub.is_active {
   510→                    Style::default()
   511→                } else {
   512→                    Style::default().fg(Color::DarkGray)
   513→                })
   514→            })
   515→            .collect();
   516→
   517→        let header = Row::new(vec!["Service", "Usage", "Limit", "Resets", "Action"])
   518→            .style(
   519→                Style::default()
   520→                    .fg(Color::Gray)
   521→                    .add_modifier(Modifier::BOLD),
   522→            )
   523→            .bottom_margin(0);
   524→
   525→        let widths = [
   526→            Constraint::Length(12),
   527→            Constraint::Length(9),
   528→            Constraint::Length(7),
   529→            Constraint::Length(10),
   530→            Constraint::Length(11),
   531→        ];
   532→
   533→        let table = Table::new(rows, widths).header(header).column_spacing(1);
   534→
   535→        ratatui::widgets::Widget::render(table, area, buf);
   536→    }
   537→
   538→    /// Render usage bars below the table.
   539→    #[allow(dead_code)]
   540→    fn render_usage_bars(&self, area: Rect, buf: &mut Buffer) {
   541→        let mut lines = Vec::new();
   542→
   543→        for sub in &self.data.subscriptions {
   544→            if sub.limit.is_some() {
   545→                let pct = sub.usage_pct();
   546→                let color = sub.usage_color();
   547→                let bar_width = 15.min(area.width.saturating_sub(20) as usize);
   548→
   549→                // Service name and bar
   550→                let bar = render_usage_bar(pct, bar_width, color);
   551→                lines.push(Line::from(vec![Span::styled(
   552→                    format!("{:<12}", sub.service.short_name()),
   553→                    Style::default().fg(Color::White),
   554→                )]));
   555→                lines.push(bar);
   556→                lines.push(Line::from(vec![Span::styled(
   557→                    format!(
   558→                        "{:>5}/{:<5} ({:.0}%)",
   559→                        sub.current_usage,
   560→                        sub.limit.unwrap_or(0),
   561→                        pct
   562→                    ),
   563→                    Style::default().fg(Color::Gray),
   564→                )]));
   565→                lines.push(Line::from(""));
   566→            }
   567→        }
   568→
   569→        if lines.is_empty() {
   570→            lines.push(Line::from(Span::styled(
   571→                "No usage data",
   572→                Style::default().fg(Color::Gray),
   573→            )));
   574→        }
   575→
   576→        let paragraph = Paragraph::new(lines);
   577→        paragraph.render(area, buf);
   578→    }
   579→}
