   590→            Style::default().fg(Color::DarkGray)
   591→        };
   592→
   593→        // Title style: bold + bright for focused, dim for unfocused
   594→        let title_style = if self.focused {
   595→            Style::default()
   596→                .fg(Color::LightCyan)
   597→                .add_modifier(Modifier::BOLD)
   598→        } else {
   599→            Style::default().fg(Color::DarkGray)
