   609→
   610→        let inner = block.inner(area);
   611→        block.render(area, buf);
   612→
   613→        // Handle special states
   614→        if self.data.is_loading {
   615→            let loading = Paragraph::new("Loading subscription data...")
   616→                .style(Style::default().fg(Color::Yellow));
   617→            loading.render(inner, buf);
   618→            return;
   619→        }
   620→
   621→        if let Some(ref error) = self.data.error {
   622→            let err =
   623→                Paragraph::new(format!("Error: {}", error)).style(Style::default().fg(Color::Red));
