   625→            return;
   626→        }
   627→
   628→        if !self.data.has_data() {
   629→            let no_data = Paragraph::new(
   630→                "No subscription data.\n\n\
   631→                 Configure subscriptions in:\n\
   632→                 ~/.forge/subscriptions.yaml",
