   746→/// Format subscription data for text-based display in the Utilization panel.
   747→pub fn format_subscription_summary(data: &SubscriptionData) -> String {
   748→    if data.is_loading {
   749→        return "Loading subscription data...".to_string();
   750→    }
   751→
   752→    if !data.has_data() {
   753→        return "No subscriptions configured.\n\n\
   754→                Configure subscriptions in:\n\
   755→                ~/.forge/subscriptions.yaml"
   756→            .to_string();
   757→    }
   758→
   759→    let mut lines = Vec::new();
   760→
   761→    lines.push("Subscription Status:".to_string());
   762→    lines.push(String::new());
   763→
   764→    for sub in &data.subscriptions {
   765→        if !sub.is_active {
   766→            continue;
   767→        }
   768→
   769→        let action = sub.recommended_action();
   770→
   771→        if let Some(limit) = sub.limit {
   772→            let pct = sub.usage_pct();
   773→            let bar_width: usize = 10;
   774→            let filled = ((pct / 100.0) * bar_width as f64).round() as usize;
   775→            let empty = bar_width.saturating_sub(filled);
   776→            let bar = format!("[{}{}]", "█".repeat(filled), "░".repeat(empty));
   777→
   778→            lines.push(format!(
   779→                "{} {} {}/{}",
   780→                sub.service.short_name(),
   781→                bar,
   782→                sub.current_usage,
   783→                limit
   784→            ));
   785→            lines.push(format!(
   786→                "  Reset: {}  {} {}",
   787→                sub.format_reset_timer(),
   788→                action.icon(),
   789→                action.description()
   790→            ));
   791→        } else if let Some(spend) = sub.daily_spend {
   792→            lines.push(format!(
   793→                "{} [Pay/Use] ${:.2}/day",
   794→                sub.service.short_name(),
   795→                spend
   796→            ));
   797→            lines.push(format!(
   798→                "  Billing: Monthly  {} {}",
   799→                action.icon(),
   800→                action.description()
   801→            ));
   802→        }
   803→
   804→        lines.push(String::new());
   805→    }
   806→
   807→    // Remove trailing empty line
   808→    if lines.last().map_or(false, |l| l.is_empty()) {
   809→        lines.pop();
   810→    }
   811→
   812→    lines.join("\n")
   813→}
